                        throw new RuntimeException("Could not create directory: " + entryPath, e);
                    }
                } else {
                    // Ensure parent directories exist
                    Path parentPath = entryPath.getParent();
                    if (parentPath != null) {
                        try {
                            Files.createDirectories(parentPath);
                        } catch (IOException e) {
                            throw new RuntimeException("Could not create parent directory: " + parentPath, e);
                        }
                    }

                    // Extract file
                    try {
                        Files.copy(zis, entryPath, StandardCopyOption.REPLACE_EXISTING);
                        extractedFiles.add(entryPath.toString());
                    } catch (IOException e) {
                        throw new RuntimeException("Could not extract file: " + entryPath, e);
                    }
                }
                zis.closeEntry();
            }
        } catch (IOException e) {
            throw new RuntimeException("Failed to extract ZIP file: " + e.getMessage(), e);
        }

        return extractedFiles;
    }
}
